    _own_ref: transaction.OutputReference,
    self: Transaction,
  ) -> Bool {
    let qualifying_lovelace: List<Int> =
      list.filter_map(
        self.inputs,
        fn(input: Input) -> Option<Int> {
          let val = input.output.value
          if assets.quantity_of(val, policy_id, assets.ada_asset_name) > 0 {
            Some(assets.lovelace_of(val))
          } else {
            None
          }
        },
      )

    let total = list.foldl(qualifying_lovelace, 0, fn(amt, acc) { acc + amt })
    total >= min_total
  }

  else(_) {
    fail
  }
}
