    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let (first_two, rest) = list.span(self.inputs, 2)
    // first_two always has at most 2 inputs
    let _ = first_two
    if list.is_empty(rest) {
      True
    } else {
      // Require at least one extra signatory when there are remaining inputs
      !list.is_empty(self.extra_signatories)
    }
  }
}
