    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let valido = interval.is_entirely_after(self.validity_range, 1000)
    if !valido {
      trace interval.to_string(self.validity_range)
      False
    } else {
      True
    }
  }
}
```

Si el rango de validez no está completamente después del bloque 1000, se traza su representación en cadena de texto mediante `interval.to_string` y se rechaza la transacción.

