use cardano/transaction.{OutputReference, Transaction}

pub type Datum {
  a: Int,
  b: Int,
}

validator tolerance_check {
  spend(
    datum: Option<Datum>,
    redeemer: Int,
    _own_ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      Some(d) -> {
        let tolerance = redeemer
        math.abs(d.a - d.b) <= tolerance
      }
      None -> False
    }
  }
}
