fn list_max(values: List<Int>) -> Int {
  when list.head(values) is {
    None -> 0 // no debería ocurrir según la precondición
    Some(first) ->
      list.foldl(
        values,
        first,
        fn(elem, acc) { math.max(acc, elem) },
      )
  }
}

// Ejemplos:
// list_max([3, 1, 4, 1, 5, 9, 2]) == 9
// list_max([7])                   == 7
