```aiken
use aiken/primitive/bytearray
use aiken/option
use cardano/transaction.{Transaction, OutputReference}

validator keyword_gate {
  spend(
    datum: Option<ByteArray>,
    redeemer: ByteArray,
    _own_ref: OutputReference,
    _self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(keyword) ->
        bytearray.index_of(redeemer, keyword)
          |> option.is_some()
    }
  }
}
```

**How it works:**
- The datum carries the required keyword.
- `bytearray.index_of(redeemer, keyword)` returns `Some((start, end))` if the keyword appears anywhere in the redeemer bytes.
- `option.is_some()` converts the result to `Bool`.
- If the datum is absent the spend is denied.

```aiken
use aiken/primitive/bytearray
use aiken/option
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}

const required_prefix: ByteArray = "nft_"

validator nft_prefix_policy {
  mint(redeemer: Void, policy_id: PolicyId, self: Transaction) -> Bool {
    let minted_tokens = assets.tokens(self.mint, policy_id)

    let all_names_have_prefix =
      minted_tokens
        |> dict_to_list_of_keys()

    // Verify every minted asset name starts with "nft_"
    // index_of returns Some((0, 3)) if "nft_" starts at position 0
    list.all(
      all_names_have_prefix,
      fn(asset_name) {
        when bytearray.index_of(asset_name, required_prefix) is {
          Some((start, _end)) -> start == 0
          None -> False
        }
      },
    )
  }
}

fn dict_to_list_of_keys(d: Dict<ByteArray, Int>) -> List<ByteArray> {
  dict.keys(d)
}
```

**Lógica clave:**
- `bytearray.index_of(asset_name, "nft_")` devuelve `Some((0, 3))` si el nombre **empieza** con `"nft_"`.
- Si `start == 0`, el prefijo está al inicio del nombre.
- Si el resultado es `None` o `start != 0`, se rechaza el mint.

