use cardano/transaction.{Transaction}

validator script_only_withdraw {
  withdraw(redeemer: Void, account: Credential, self: Transaction) -> Bool {
    when account is {
      Script(_) -> True
      VerificationKey(_) -> False
    }
  }
}
```

Puedes usar `list.any` para comprobar si alguna credencial en la lista es de tipo `Script`:

```aiken
use cardano/address.{Credential, Script}
use aiken/collection/list

fn has_script_credential(creds: List<Credential>) -> Bool {
  list.any(creds, fn(cred) {
    when cred is {
      Script(_) -> True
      _ -> False
    }
  })
}
```

La función `list.any` recorre la lista y devuelve `True` en cuanto encuentra un elemento que satisface el predicado.

