```aiken
use cardano/assets
use cardano/transaction.{Transaction, Output}
use aiken/collection/list

validator min_lovelace_output {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    _own_ref: transaction.OutputReference,
    self: Transaction,
  ) -> Bool {
    let total_lovelace: assets.Lovelace =
      list.foldl(
        self.outputs,
        0,
        fn(output: Output, acc: Int) -> Int {
          acc + assets.lovelace_of(output.value)
        },
      )
    total_lovelace >= 5_000_000
  }
}
