use cardano/transaction.{Transaction, Output}
use aiken/collection/list

fn sum_outputs(outputs: List<Output>) -> Lovelace {
  list.foldl(outputs, 0, fn(o: Output, acc: Lovelace) -> Lovelace {
    acc + assets.lovelace_of(o.value)
