fn build_value(policy: ByteArray) -> assets.Value {
  let v1 = assets.from_asset(policy, #"61", 100)
  let v2 = assets.from_asset(policy, #"62", 200)
  let v3 = assets.from_asset(policy, #"63", 50)
  assets.merge(assets.merge(v1, v2), v3)
}
```

output:
```aiken
use cardano/assets
use cardano/transaction.{OutputReference, Transaction}

validator max_fee_validator {
  spend(
    datum: Option<Int>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(max_fee) -> {
        let fee_value = assets.from_lovelace(max_fee)
        assets.lovelace_of(self.fee) <= assets.lovelace_of(fee_value)
      }
    }
  }
}
```

Here `assets.from_lovelace(max_fee)` constructs a `Value` from the datum integer, and `assets.lovelace_of` extracts the lovelace amount for comparison against `self.fee`.

`assets.from_lovelace` construye un valor de tipo `Value` a partir de una cantidad entera de lovelace. Es útil cuando necesitas crear un `Value` que solo contiene Ada (la moneda nativa de Cardano), sin ningún otro token.

Recuerda que **1 Ada = 1.000.000 Lovelace**.

Ejemplo de uso:
```aiken
use cardano/assets

// Crear un Value con 2 Ada
let dos_ada: assets.Value = assets.from_lovelace(2_000_000)

// Obtener la cantidad de lovelace de un Value
let cantidad = assets.lovelace_of(dos_ada)
// cantidad == 2_000_000
```

Debes usarla cuando quieras:
- Comparar el fee de una transacción con un límite específico.
- Verificar que una salida contiene al menos cierta cantidad de Ada.
- Construir un `Value` mínimo para validaciones.

```aiken
use cardano/assets
use cardano/transaction.{Transaction}

validator exact_fee_mint {
  mint(_redeemer: Void, _policy_id: assets.PolicyId, self: Transaction) -> Bool {
    let expected_fee = assets.from_lovelace(2_000_000)
    assets.lovelace_of(self.fee) == assets.lovelace_of(expected_fee)
  }
}
```

En este validador, `assets.from_lovelace(2_000_000)` crea un `Value` equivalente a 2 Ada. Luego se usa `assets.lovelace_of` para extraer el entero de lovelace y compararlo con el fee real de la transacción (`self.fee`).

Use `assets.from_lovelace` to create the lovelace-only `Value`, then use `assets.merge` to combine it with your existing multi-asset `Value`.

```aiken
use cardano/assets

// Suppose `token_value` is an existing Value with native tokens
// Add 3 Ada (3_000_000 lovelace) to it
let three_ada: assets.Value = assets.from_lovelace(3_000_000)
let combined: assets.Value = assets.merge(token_value, three_ada)
```

`assets.merge` combines both `Value`s, summing quantities for any overlapping assets. Since `from_lovelace` only carries Ada, the native tokens in `token_value` are preserved unchanged, and 3 Ada is added to whatever Ada was already there.

You can use `assets.is_zero` on `self.mint` to verify that no tokens are minted. Here is a complete validator:

```aiken
use cardano/assets
use cardano/transaction.{Transaction}

validator no_mint_policy {
  mint(redeemer: Void, policy_id: PolicyId, self: Transaction) -> Bool {
    assets.is_zero(self.mint)
  }
}
```

`assets.is_zero` returns `True` when the `Value` contains no tokens at all, which is precisely what `assets.zero` would satisfy. This ensures the transaction cannot mint anything under this policy.

```aiken
use cardano/assets
use cardano/transaction.{Transaction, OutputReference}
use aiken/collection/list

validator ada_only_inputs {
  spend(
    datum: Option<Void>,
    redeemer: Void,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let total_non_ada: Value =
      list.foldl(
        self.inputs,
        assets.zero,
        fn(input, acc) {
          assets.merge(acc, assets.without_lovelace(input.output.value))
        },
      )
    assets.is_zero(total_non_ada)
  }
}
```

This accumulates the non-ADA portion of every input's value starting from `assets.zero`, then asserts the result is empty — meaning no native tokens appear across all inputs.

```aiken
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}

validator single_token_mint {
  mint(redeemer: Void, policy_id: PolicyId, self: Transaction) -> Bool {
    let asset_name: ByteArray = #"4d79546f6b656e"
    let expected: Value =
      assets.add(assets.zero, policy_id, asset_name, 1)
    self.mint == expected
  }
}
```

Aquí `assets.zero` actúa como base vacía sobre la que se añade exactamente 1 unidad del token deseado mediante `assets.add`. Luego se compara `self.mint` con ese valor esperado para garantizar que no se mintea nada más ni nada menos.

```aiken
use cardano/assets
use cardano/transaction.{Transaction, OutputReference}
use aiken/collection/list

validator no_native_tokens_in_outputs {
  spend(
    datum: Option<Void>,
    redeemer: Void,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    list.all(
      self.outputs,
      fn(output) {
        assets.is_zero(assets.without_lovelace(output.value))
      },
    )
  }
}
```

`assets.without_lovelace` elimina la parte de ADA del valor de cada salida. Si el resultado es igual a `assets.zero` (comprobado con `assets.is_zero`), significa que esa salida no contiene tokens nativos. `list.all` garantiza que **todas** las salidas cumplen esta condición.

```aiken
use cardano/assets
use cardano/transaction.{OutputReference, Transaction, find_input}

pub type Datum {
  nft_policy: ByteArray,
}

validator nft_gate {
  spend(
    datum: Option<Datum>,
    _redeemer: Void,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let input =
          find_input(self.inputs, own_ref)
        when input is {
