// Before (verbose manual approach):
// let policies = assets.policies(value)
// let non_ada_policies = list.filter(policies, fn(p) { p != assets.ada_policy_id })
// let only_one_policy = list.length(non_ada_policies) == 1
// let tokens_under_policy = assets.tokens(value, my_policy)
// let only_one_token = ... (quantity checks)

// After (clean, idiomatic):
let is_clean_nft = assets.has_any_nft_strict(value, my_policy)
