// Si el activo no existe, esto retorna 0
let qty = assets.quantity_of(some_value, policy_id, asset_name)
// qty == 0 si no está presente
```

Esta semántica facilita verificaciones como `qty >= min_required` sin casos especiales.

```aiken
use cardano/assets
use cardano/transaction.{Transaction}

validator ticket_minter {
  mint(
    _redeemer: Void,
    policy_id: assets.PolicyId,
    self: Transaction,
  ) -> Bool {
    let asset_name: assets.AssetName = "TICKET"
    let minted_qty = assets.quantity_of(self.mint, policy_id, asset_name)
    minted_qty == 1
  }
}
```

Aquí `self.mint` es el `Value` que representa los tokens acuñados en la transacción. `assets.quantity_of` extrae exactamente cuántos tokens con ese `policy_id` y `asset_name` se están acuñando, y validamos que sea exactamente `1`.

```aiken
use cardano/assets
use cardano/transaction.{OutputReference, Transaction, Input, Output}

const token_policy: assets.PolicyId = #"deadbeefdeadbeefdeadbeefdeadbeefdeadbeefdeadbeefdeadbeef"
const token_name: assets.AssetName = "REWARD"
const min_quantity: Int = 10

validator token_guard {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    // Encontrar el input que se está gastando
    expect Some(own_input) =
      self.inputs
        |> transaction.find_input(_, own_ref)

    let qty =
      assets.quantity_of(own_input.output.value, token_policy, token_name)

    qty >= min_quantity
  }
}
```

Usamos `transaction.find_input` para localizar el input propio mediante `own_ref`, luego `assets.quantity_of` sobre su `value` para verificar que hay al menos `10` unidades del token requerido.

```aiken
use cardano/assets
use aiken/collection/dict

validator nft_mint {
  mint(redeemer: Void, policy_id: PolicyId, self: Transaction) -> Bool {
    let expected_name: ByteArray = #"636f6f6c746f6b656e"
    let minted_tokens = assets.tokens(self.mint, policy_id)
    // Must have exactly one entry with qty 1
    dict.size(minted_tokens) == 1 && dict.get(minted_tokens, expected_name) == Some(1)
  }
}
```

`assets.tokens(self.mint, policy_id)` scopes the minted value down to only this policy's tokens, making it easy to assert both the name and quantity.

```aiken
use cardano/assets
use cardano/transaction.{Output, OutputReference, Transaction, find_input}
use aiken/collection/dict

pub type Datum {
  required_policy: ByteArray,
}

validator policy_gating {
  spend(
    datum: Option<Datum>,
    _redeemer: Void,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(d) = datum
    expect Some(input) = find_input(self.inputs, own_ref)
    let tok = assets.tokens(input.output.value, d.required_policy)
    !dict.is_empty(tok)
  }
