use aiken/collection/list

fn get_spend_redeemer(
  redeemers: Pairs<ScriptPurpose, Redeemer>,
  target: OutputReference,
) -> Option<Redeemer> {
  list.find_map(
    redeemers,
    fn(pair) {
      let (purpose, rdmr) = pair
      when purpose is {
        Spend(oref) if oref == target -> Some(rdmr)
        _ -> None
      }
    },
  )
}
