```aiken
use aiken/collection/list
use cardano/transaction.{Transaction, OutputReference, ScriptPurpose, Redeemer}
use cardano/assets.{PolicyId}

// Helper: decode a Redeemer (Data) as Int, returning None if it isn't one.
fn redeemer_as_int(rdmr: Redeemer) -> Option<Int> {
  if rdmr is i: Int {
    Some(i)
  } else {
    None
  }
}

validator mint_guard {
  spend(
    _datum: Option<Void>,
    _redeemer: Void,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    // Collect only Mint-purpose redeemers
    let mint_redeemers: List<Redeemer> =
      list.filter_map(
        self.redeemers,
        fn(pair) {
          let (purpose, rdmr) = pair
          when purpose is {
            Mint(_) -> Some(rdmr)
            _ -> None
          }
        },
      )

    // Reject if any mint redeemer decodes to an Int > 100
    list.all(
      mint_redeemers,
      fn(rdmr) {
        when redeemer_as_int(rdmr) is {
          Some(n) -> n <= 100
          None -> True
        }
      },
    )
  }
}
```

`self.redeemers` is `Pairs<ScriptPurpose, Redeemer>` and `Redeemer = Data`, so you can pattern-match on the `ScriptPurpose` to isolate mint redeemers and then attempt to decode the opaque `Data` into the expected shape.

