```aiken
use cardano/assets
use cardano/transaction

validator example {
  spend(
    _datum: Option<Data>,
    _redeemer: Data,
    own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    expect Some(own_input) = self.inputs |> transaction.find_input(own_ref)
    assets.lovelace_of(own_input.output.value) > 0
