```aiken
// Existing (non-idiomatic) approach
use cardano/transaction.{Transaction, OutputReference, Output, Datum, InlineDatum}
use aiken/collection/list

fn resolve_datum_manual(
  outputs: List<Output>,
  target_hash: ByteArray,
) -> Option<Data> {
